# Explorer notes for S47-T1-A-E2: follow packet fixture + instruction contract
def assess(record: dict) -> str:
    required = {'rerun_metric', 'tolerance', 'seed', 'params', 'case_id', 'metric'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if abs(record["metric"] - record["rerun_metric"]) <= record["tolerance"] else "MARK_RUN_NONREPRODUCIBLE"

valid = {'case_id': 'CASO-TAC-047-1A', 'seed': 42, 'params': {'depth': 4}, 'metric': 0.81, 'rerun_metric': 0.805, 'tolerance': 0.01}
invalid = {'case_id': 'CASO-TAC-047-1A', 'seed': 42, 'params': {'depth': 4}, 'metric': 100.81, 'rerun_metric': 0.805, 'tolerance': 0.01}
incomplete = {**valid}
incomplete.pop('tolerance', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

